namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    private static readonly List<RecipeCategory> _categories =
    [
        new() { Name = "Breakfast", Description = "Start your day right", Icon = "🍳" },
        new() { Name = "Lunch", Description = "Midday meals and sandwiches", Icon = "🥪" },
        new() { Name = "Dinner", Description = "Hearty evening dishes", Icon = "🍝" },
        new() { Name = "Desserts", Description = "Sweet treats and baked goods", Icon = "🍰" },
        new() { Name = "Snacks", Description = "Quick bites and appetizers", Icon = "🥨" },
        new() { Name = "Drinks", Description = "Beverages and smoothies", Icon = "🥤" },
    ];

    public RecipeService()
    {
        _recipes =
        [
            new()
            {
                Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
                Ingredients = ["2 cups flour", "2 eggs", "1.5 cups milk", "2 tbsp sugar", "1 tsp baking powder"],
                Steps = ["Mix dry ingredients", "Whisk eggs and milk together", "Combine wet and dry", "Cook on griddle until golden"],
                Ratings = [4, 5, 5, 4]
            },
            new()
            {
                Id = 2, Title = "Grilled Cheese Sandwich", Category = "Lunch",
                Ingredients = ["2 slices bread", "2 slices cheddar", "1 tbsp butter"],
                Steps = ["Butter bread slices", "Place cheese between bread", "Grill on medium heat until golden", "Flip and grill other side"],
                Ratings = [5, 4, 5]
            },
            new()
            {
                Id = 3, Title = "Spaghetti Bolognese", Category = "Dinner",
                Ingredients = ["400g spaghetti", "500g ground beef", "1 can crushed tomatoes", "1 onion", "3 cloves garlic", "Italian herbs"],
                Steps = ["Cook pasta according to package", "Sauté onion and garlic", "Brown the beef", "Add tomatoes and herbs, simmer 20 min", "Serve sauce over pasta"],
                Ratings = [5, 5, 4, 5, 4]
            },
            new()
            {
                Id = 4, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Ingredients = ["2.25 cups flour", "1 cup butter", "0.75 cup sugar", "0.75 cup brown sugar", "2 eggs", "1 tsp vanilla", "2 cups chocolate chips"],
                Steps = ["Cream butter and sugars", "Beat in eggs and vanilla", "Mix in flour", "Fold in chocolate chips", "Bake at 375°F for 9-11 minutes"],
                Ratings = [5, 5, 5, 4, 5]
            },
            new()
            {
                Id = 5, Title = "Trail Mix", Category = "Snacks",
                Ingredients = ["1 cup almonds", "1 cup cashews", "0.5 cup raisins", "0.5 cup chocolate chips", "0.5 cup dried cranberries"],
                Steps = ["Combine all ingredients in a bowl", "Mix well", "Store in airtight container"],
                Ratings = [4, 3, 4]
            },
            new()
            {
                Id = 6, Title = "Berry Smoothie", Category = "Drinks",
                Ingredients = ["1 cup mixed berries", "1 banana", "1 cup yogurt", "0.5 cup milk", "1 tbsp honey"],
                Steps = ["Add all ingredients to blender", "Blend until smooth", "Pour and serve immediately"],
                Ratings = [5, 4, 5, 5]
            },
        ];
        _nextId = 7;
    }

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int rating)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && rating is >= 1 and <= 5)
        {
            recipe.Ratings.Add(rating);
        }
    }

    public Recipe AddRecipe(string title, string category, List<string> ingredients, List<string> steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

