@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= CurrentRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              title="@star star(s)">★</span>
    }
    @if (TotalRatings > 0)
    {
        <span class="rating-info">(@AverageRating.ToString("F1") avg, @TotalRatings ratings)</span>
