    private int CurrentRating { get; set; }

    private async Task Rate(int rating)
    {
        CurrentRating = rating;
        await OnRated.InvokeAsync(rating);
    }
}

.star-rating {
    display: inline-flex;
    align-items: center;
    gap: 2px;
}

.star {
    font-size: 1.5rem;
    cursor: pointer;
    color: #ddd;
    transition: color 0.2s;
}

.star:hover,
.star.filled {
    color: #ffc107;
}

.rating-info {
    margin-left: 0.5rem;
    font-size: 0.85rem;
    color: #666;
}

