                    }
                </InputSelect>
            </div>

            <div class="mb-3">
                <label class="form-label">Ingredients (one per line)</label>
                <InputTextArea @bind-Value="IngredientsText" class="form-control" rows="5"
                               placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            </div>

            <div class="mb-3">
                <label class="form-label">Steps (one per line)</label>
                <InputTextArea @bind-Value="StepsText" class="form-control" rows="5"
                               placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Bake for 30 minutes" />
            </div>

            <button type="submit" class="btn btn-success"
                    disabled="@(!IsValid)">
                Submit Recipe
