    private string StepsText { get; set; } = string.Empty;
    private bool Submitted { get; set; }
    private int SubmittedRecipeId { get; set; }

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(Title) &&
        !string.IsNullOrWhiteSpace(SelectedCategory) &&
        !string.IsNullOrWhiteSpace(IngredientsText) &&
        !string.IsNullOrWhiteSpace(StepsText);

    private void HandleSubmit()
    {
        if (!IsValid) return;

        var ingredients = IngredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        var steps = StepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        var recipe = RecipeService.AddRecipe(Title, SelectedCategory, ingredients, steps);
        SubmittedRecipeId = recipe.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Title = string.Empty;
        SelectedCategory = string.Empty;
        IngredientsText = string.Empty;
        StepsText = string.Empty;
        Submitted = false;
    }
}

