        </div>
        <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
    }
    else
    {
        <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
            <div class="mb-3">
                <label class="form-label">Title</label>
                <InputText @bind-Value="Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            </div>

            <div class="mb-3">
                <label class="form-label">Category</label>
                <InputSelect @bind-Value="SelectedCategory" class="form-select">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in RecipeService.GetCategories())
                    {
                        <option value="@cat.Name">@cat.Icon @cat.Name</option>
                    }
                </InputSelect>
            </div>

            <div class="mb-3">
                <label class="form-label">Ingredients (one per line)</label>
                <InputTextArea @bind-Value="IngredientsText" class="form-control" rows="5"
                               placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            </div>

            <div class="mb-3">
                <label class="form-label">Steps (one per line)</label>
                <InputTextArea @bind-Value="StepsText" class="form-control" rows="5"
                               placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Bake for 30 minutes" />
            </div>

            <button type="submit" class="btn btn-success"
                    disabled="@(!IsValid)">
                Submit Recipe
            </button>
        </EditForm>
    }
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private string Title { get; set; } = string.Empty;
    private string SelectedCategory { get; set; } = string.Empty;
    private string IngredientsText { get; set; } = string.Empty;
    private string StepsText { get; set; } = string.Empty;
    private bool Submitted { get; set; }
    private int SubmittedRecipeId { get; set; }

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(Title) &&
        !string.IsNullOrWhiteSpace(SelectedCategory) &&
        !string.IsNullOrWhiteSpace(IngredientsText) &&
        !string.IsNullOrWhiteSpace(StepsText);

    private void HandleSubmit()
    {
        if (!IsValid) return;

        var ingredients = IngredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        var steps = StepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        var recipe = RecipeService.AddRecipe(Title, SelectedCategory, ingredients, steps);
        SubmittedRecipeId = recipe.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Title = string.Empty;
        SelectedCategory = string.Empty;
        IngredientsText = string.Empty;
        StepsText = string.Empty;
        Submitted = false;
    }
}

